const payload = $json.body && Object.keys($json.body).length ? $json.body : $json;
const headers = $json.headers || {};
const normalizedHeaders = Object.fromEntries(Object.entries(headers).map(([key, value]) => [String(key).toLowerCase(), value]));
const providedSecret = normalizedHeaders['x-zagchain-webhook-secret'] || '';
const expectedSecret = 'replace-with-your-n8n-secret';
const event = payload.event || 'unknown';

if (providedSecret !== expectedSecret) {
  return [{
    ok: false,
    error: 'Invalid webhook secret.',
    event,
    route: 'rejected',
    data: payload.data || null,
  }];
}

let route = 'unhandled';
let summary = 'Unhandled ZagChain event received.';

if (event === 'user.registered') {
  route = 'user_registered';
  summary = `New registration: ${payload?.data?.user?.name || 'Unknown user'} (${payload?.data?.user?.email || 'no email'})`;
}

if (event === 'kyc.submitted') {
  route = 'kyc_submitted';
  summary = `New KYC submission: ${payload?.data?.user?.name || 'Unknown user'} (${payload?.data?.user?.email || 'no email'})`;
}

if (event === 'payout.requested') {
  route = 'payout_requested';
  summary = `New payout request: ${payload?.data?.user?.name || 'Unknown user'} requested ${payload?.data?.payout?.amount || 0}`;
}

return [{
  ok: true,
  event,
  route,
  summary,
  occurred_at: payload.occurred_at || new Date().toISOString(),
  app: payload.app || null,
  data: payload.data || null,
  next_steps: [
    'Attach an IF or Switch node after this Code node using the route field.',
    'Send admin alerts with Gmail, SMTP, Telegram, Slack, or WhatsApp integrations.',
    'Store the event in Google Sheets, Airtable, Notion, HubSpot, or your CRM.'
  ]
}];
